import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const API_URL = 'http://localhost:3000'; // Adjust to your backend URL

const ContactForm = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    name: "",
    phone_number: "",
    email: "",
    message: ""
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch(`${API_URL}/contact_messages`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json', // Important for JSON
        },
        body: JSON.stringify({ contact_message: formData }), // Sending the object
      });

      if (response.ok) {
        const result = await response.json();
        alert(result.message || 'Message sent successfully!');
        setFormData({
          name: "",
          phone_number: "",
          email: "",
          message: ""
        });
        navigate("/thankyoumessage");
      } else {
        const errorData = await response.json();
        console.error('Error details:', errorData);
        alert('Error: ' + (errorData.errors || errorData.error || 'Unexpected error.'));
      }
    } catch (error) {
      console.error('Error:', error);
      alert('There was an error sending your message. Please try again later.');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input type="text" name="name" value={formData.name} onChange={handleChange} required />
      <input type="tel" name="phone_number" value={formData.phone_number} onChange={handleChange} required />
      <input type="email" name="email" value={formData.email} onChange={handleChange} required />
      <textarea name="message" value={formData.message} onChange={handleChange} required></textarea>
      <button type="submit">Submit</button>
    </form>
  );
};

export default ContactForm;
